class Solution {
public:
    int maxTaskAssign(vector<int>& tasks, vector<int>& workers, int pills, int strength) {
        int result = 0;
        for (int i = 0; i < tasks.size(); i++) {
            for (int j = 0; j < workers.size(); j++) {
                if (tasks[i] <= workers[j] + pills) {
                    result = max(result, tasks[i]);
                    workers[j] += pills;
                }
            }
        }
        return result;
    }
};
```

